def lec_column_by_slug(slug: str) -> Optional[Dict[str, Any]]:
    for e in LEC_COLUMN_ENTRIES:
        if e.get("slug") == slug:
            return e
    return None


def lec_column_entries_english_live() -> List[Dict[str, Any]]:
    """英語版コラム一覧用（title_en がある live のみ）。"""
    return [
        e
        for e in LEC_COLUMN_ENTRIES
        if e.get("status") == "live" and e.get("title_en")
    ]


def lec_column_has_english(entry: Optional[Dict[str, Any]]) -> bool:
    return bool(entry and entry.get("status") == "live" and entry.get("title_en"))
